<?php
namespace App\Http\Controllers;use App\Domain\Hunts\Sessions\Exceptions\ActiveHuntingSessionExistsException;use App\Domain\Hunts\Sessions\HuntingSessionService;use App\Models\Character;use App\Models\HuntingSession;use App\Models\Zone;use Illuminate\Http\Request;class CharacterHuntingSessionController extends Controller{public function store(Character $character,Zone $zone,HuntingSessionService $service){$this->authorize('view',$character);try{$result=$service->start($character,$zone);return redirect()->route('characters.hunting-sessions.show',[$character,$result->id()]);}catch(ActiveHuntingSessionExistsException $e){return redirect()->route('zones.show',$zone)->withErrors(['hunt'=>$e->getMessage()]);}}public function show(Character $character,HuntingSession $huntingSession,HuntingSessionService $service){$this->authorize('view',$character);return view('characters.hunting-sessions.show',['character'=>$character,'session'=>$service->show($character,$huntingSession)->toArray()]);}public function tick(Character $character,HuntingSession $huntingSession,HuntingSessionService $service){$this->authorize('view',$character);return response()->json($service->tick($character,$huntingSession)->toArray());}public function stop(Request $request,Character $character,HuntingSession $huntingSession,HuntingSessionService $service){$this->authorize('view',$character);$result=$service->stop($character,$huntingSession);if($request->expectsJson())return response()->json($result->toArray());return redirect()->route('characters.hunting-sessions.show',[$character,$huntingSession])->with('status','Cacería conectada detenida.');}}
